import{_ as t,c as o,o as a,ae as n}from"./chunks/framework.D5LTYjOy.js";const m=JSON.parse('{"title":"Avenir(s) DSAV - TEST","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),i={name:"index.md"};function r(s,e,d,l,c,p){return a(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="avenir-s-dsav-test" tabindex="-1">Avenir(s) DSAV - TEST <a class="header-anchor" href="#avenir-s-dsav-test" aria-label="Permalink to &quot;Avenir(s) DSAV - TEST&quot;">​</a></h1><h2 id="what-is-dsav" tabindex="-1">What is DSAV? <a class="header-anchor" href="#what-is-dsav" aria-label="Permalink to &quot;What is DSAV?&quot;">​</a></h2><p>DSAV is the deisgn system for AVENIR(s) projects and consists of an <strong>adaptation</strong> of <a href="https://vue-ds.fr/" target="_blank" rel="noreferrer"><strong>VueDSFR</strong></a> into a <a href="https://v3.vuejs.org/" target="_blank" rel="noreferrer"><strong>Vue 3</strong></a> project in the form of a <strong>component library</strong>.</p><p>The code is <a href="https://github.com/avenirs-esr/avenirs-dsav/" target="_blank" rel="noreferrer">open and available on GitHub</a></p><h2 id="why-dsav" tabindex="-1">Why DSAV? <a class="header-anchor" href="#why-dsav" aria-label="Permalink to &quot;Why DSAV?&quot;">​</a></h2><p>The AVENIR(s) program has chosen its technical stack for the front end, based on Vue 3. VueDSFR offers a component library based on <a href="https://www.systeme-de-design.gouv.fr/" target="_blank" rel="noreferrer"><strong>French Design System</strong></a>.</p><p>The AVENIR(s) program needs its own identity, hence this adaptation of VueDSFR.</p><h2 id="complete-documentation" tabindex="-1">Complete documentation <a class="header-anchor" href="#complete-documentation" aria-label="Permalink to &quot;Complete documentation&quot;">​</a></h2><p>You can find the complete documentation on our <a href="https://avenirs-esr.github.io/avenirs-dsav/" target="_blank" rel="noreferrer">github page</a>.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>In your project, run <code>npm install @ævenirs-esr/avenirs-dsav</code>.</p><p>In order to make the style from <code>DSAV</code> work in your project, make sure to import the main <code>DSAV</code> style in your <code>main.ts</code> with the following : <code>import &#39;@avenirs-esr/avenirs-dsav/dist/avenirs-dsav.css&#39;</code>.</p><h2 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h2><h3 id="deploying-a-new-npm-version" tabindex="-1">Deploying a new npm version <a class="header-anchor" href="#deploying-a-new-npm-version" aria-label="Permalink to &quot;Deploying a new npm version&quot;">​</a></h3><p>When your development is successfully merged in <code>develop</code> or <code>main</code>, you can run the job <code>Release new version to npm</code> and select the type of version bump : <code>patch</code>, <code>minor</code> or <code>release</code>.</p><h3 id="commit-conventions" tabindex="-1">Commit conventions <a class="header-anchor" href="#commit-conventions" aria-label="Permalink to &quot;Commit conventions&quot;">​</a></h3><p>This repository uses <a href="https://commitlint.js.org/" target="_blank" rel="noreferrer">Commitlint</a> to enforce consistent and conventional commit messages.</p><p>This setup extends the conventional commit configuration (<code>@commitlint/config-conventional</code>) and adds custom rules:</p><p>✅ Allowed Commit Types</p><p>The following commit types are allowed:</p><ul><li><code>feat</code> – A new feature</li><li><code>fix</code> – A bug fix</li><li><code>docs</code> – Documentation changes</li><li><code>refactor</code> – Code refactoring (no feature or bug fix)</li><li><code>test</code> – Adding or modifying tests</li><li><code>build</code> – Changes to build tools or dependencies</li><li><code>revert</code> – Revert a previous commit</li></ul><p>🔠 Commit Message Rules</p><table tabindex="0"><thead><tr><th>Rule</th><th>Description</th></tr></thead><tbody><tr><td><code>type-enum</code></td><td>Only allows the types listed above</td></tr><tr><td><code>type-case</code></td><td>Commit type must be <strong>lowercase</strong></td></tr><tr><td><code>type-empty</code></td><td>Commit type <strong>must not</strong> be empty</td></tr><tr><td><code>subject-case</code></td><td>No restriction on subject casing (rule is disabled for flexibility)</td></tr></tbody></table><p>✅ Example Commit Messages</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>feat: add user login functionality</span></span>
<span class="line"><span>fix: handle null pointer in dashboard</span></span>
<span class="line"><span>docs: update installation guide</span></span></code></pre></div><h2 id="projects-using-dsav" tabindex="-1">Projects using DSAV <a class="header-anchor" href="#projects-using-dsav" aria-label="Permalink to &quot;Projects using DSAV&quot;">​</a></h2><ul><li><a href="https://github.com/avenirs-esr/avenirs-cofolio-client" target="_blank" rel="noreferrer">AVENIR(s) Cofolio</a> : An ePortfolio for Higher Education and Research</li></ul>`,27)])])}const u=t(i,[["render",r]]);export{m as __pageData,u as default};
